import React from "react";
import { ReorderFourOutline } from "react-ionicons";
import logo from "../assets/logo.svg";
import "./menu.css";
import "../styles/global.css";

class Menu extends React.Component {
    constructor(props) {
        super(props);
        this.logo = props.logo;
        this.state = { hidden: true };
        this.handleToggle = () => {
            this.setState({ hidden: !this.state.hidden });
        };
    }

    render() {
        return (
            <header className="menu">
                {/* topbar */}
                <div className="topbar">
                    <img src={logo} alt="" width="32px" height="32px"></img>
                    <ReorderFourOutline onClick={this.handleToggle} color={'#ffffff'} height="48px" width="48px"/>
                </div>

                {/* navigation */}
                {!this.state.hidden && (
                <nav>
                    <ul><a href="#about">About</a></ul>
                    <ul><a href="#projects">Projects</a></ul>
                    <ul><a href="#contact">Contact</a></ul>
                    {/* <ul><a href="/"><strike>Blogs</strike></a></ul> */}
                </nav>
                )}
            </header>
        );
    }
}

export default Menu;
